'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { useAuth } from '@/contexts/auth-context';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Spinner } from '@/components/ui/spinner';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  ArrowLeftIcon,
  FloppyDiskIcon,
  PaperPlaneTiltIcon,
  WarningCircleIcon,
  InfoIcon,
} from '@phosphor-icons/react';

const BANK_TYPES = [
  { value: 'commercial', label: 'Commercial Bank' },
  { value: 'microfinance', label: 'Microfinance Institution' },
  { value: 'development', label: 'Development Bank' },
  { value: 'cooperative', label: 'Cooperative Bank' },
];

export default function NewApplicationPage() {
  const router = useRouter();
  const { user, permissions } = useAuth();

  const [formData, setFormData] = useState({
    bankName: '',
    bankType: '',
    businessAddress: '',
    contactEmail: user?.email || '',
    contactPhone: '',
    proposedCapital: '',
    businessPlan: '',
  });
  const [error, setError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  if (!permissions?.canCreateApplication) {
    return (
      <div className="flex flex-col items-center justify-center py-12">
        <WarningCircleIcon className="h-12 w-12 text-destructive mb-4" />
        <h1 className="text-xl font-bold">Access Denied</h1>
        <p className="text-muted-foreground mt-2">
          You do not have permission to create applications.
        </p>
        <Link href="/dashboard" className="mt-4">
          <Button>Return to Dashboard</Button>
        </Link>
      </div>
    );
  }

  const handleChange = (field: string, value: string) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    setError('');
  };

  const validateForm = () => {
    if (!formData.bankName.trim()) return 'Bank name is required';
    if (!formData.bankType) return 'Bank type is required';
    if (!formData.businessAddress.trim()) return 'Business address is required';
    if (!formData.contactEmail.trim()) return 'Contact email is required';
    if (!formData.contactPhone.trim()) return 'Contact phone is required';
    if (!formData.proposedCapital || Number(formData.proposedCapital) <= 0) {
      return 'Valid proposed capital is required';
    }
    if (!formData.businessPlan.trim()) return 'Business plan summary is required';
    return null;
  };

  const handleSubmit = async (submit: boolean) => {
    const validationError = validateForm();
    if (validationError) {
      setError(validationError);
      return;
    }

    if (submit) {
      setIsSubmitting(true);
    } else {
      setIsSaving(true);
    }

    try {
      const response = await fetch('/api/applications', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...formData, submit }),
      });

      const data = await response.json();

      if (response.ok && data.success) {
        router.push(`/applications/${data.application.id}`);
      } else {
        setError(data.error || 'Failed to save application');
      }
    } catch {
      setError('Network error. Please try again.');
    } finally {
      setIsSubmitting(false);
      setIsSaving(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-4">
        <Link href="/applications">
          <Button variant="ghost" size="sm" className="gap-2">
            <ArrowLeftIcon size={16} />
            Back
          </Button>
        </Link>
        <div>
          <h1 className="text-2xl font-bold tracking-tight">New Application</h1>
          <p className="text-muted-foreground">
            Submit a new bank licensing application
          </p>
        </div>
      </div>

      <div className="grid gap-6 lg:grid-cols-3">
        <div className="lg:col-span-2 space-y-6">
          {error && (
            <Alert variant="destructive">
              <WarningCircleIcon className="h-4 w-4" />
              <AlertDescription>{error}</AlertDescription>
            </Alert>
          )}

          <Card>
            <CardHeader>
              <CardTitle>Bank Information</CardTitle>
              <CardDescription>
                Basic information about the financial institution
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 sm:grid-cols-2">
                <div className="space-y-2">
                  <Label htmlFor="bankName">Bank Name *</Label>
                  <Input
                    id="bankName"
                    placeholder="Enter bank name"
                    value={formData.bankName}
                    onChange={(e) => handleChange('bankName', e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="bankType">Bank Type *</Label>
                  <Select
                    value={formData.bankType}
                    onValueChange={(value) => handleChange('bankType', value)}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Select bank type" />
                    </SelectTrigger>
                    <SelectContent>
                      {BANK_TYPES.map((type) => (
                        <SelectItem key={type.value} value={type.value}>
                          {type.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="businessAddress">Business Address *</Label>
                <Textarea
                  id="businessAddress"
                  placeholder="Enter full business address"
                  value={formData.businessAddress}
                  onChange={(e) => handleChange('businessAddress', e.target.value)}
                  rows={2}
                />
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Contact Information</CardTitle>
              <CardDescription>
                Primary contact details for this application
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 sm:grid-cols-2">
                <div className="space-y-2">
                  <Label htmlFor="contactEmail">Contact Email *</Label>
                  <Input
                    id="contactEmail"
                    type="email"
                    placeholder="contact@example.com"
                    value={formData.contactEmail}
                    onChange={(e) => handleChange('contactEmail', e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="contactPhone">Contact Phone *</Label>
                  <Input
                    id="contactPhone"
                    placeholder="+250 7XX XXX XXX"
                    value={formData.contactPhone}
                    onChange={(e) => handleChange('contactPhone', e.target.value)}
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Financial Information</CardTitle>
              <CardDescription>
                Capital and business plan details
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="proposedCapital">Proposed Capital (RWF) *</Label>
                <Input
                  id="proposedCapital"
                  type="number"
                  placeholder="Enter amount in RWF"
                  value={formData.proposedCapital}
                  onChange={(e) => handleChange('proposedCapital', e.target.value)}
                />
                <p className="text-xs text-muted-foreground">
                  Minimum capital requirements vary by bank type
                </p>
              </div>

              <div className="space-y-2">
                <Label htmlFor="businessPlan">Business Plan Summary *</Label>
                <Textarea
                  id="businessPlan"
                  placeholder="Provide a summary of your business plan, including objectives, target market, and key strategies..."
                  value={formData.businessPlan}
                  onChange={(e) => handleChange('businessPlan', e.target.value)}
                  rows={6}
                />
              </div>
            </CardContent>
          </Card>

          <div className="flex flex-col gap-3 sm:flex-row sm:justify-end">
            <Button
              variant="outline"
              onClick={() => handleSubmit(false)}
              disabled={isSubmitting || isSaving}
              className="gap-2"
            >
              {isSaving ? (
                <Spinner className="h-4 w-4" />
              ) : (
                <FloppyDiskIcon size={16} />
              )}
              Save as Draft
            </Button>
            <Button
              onClick={() => handleSubmit(true)}
              disabled={isSubmitting || isSaving}
              className="gap-2"
            >
              {isSubmitting ? (
                <Spinner className="h-4 w-4" />
              ) : (
                <PaperPlaneTiltIcon size={16} />
              )}
              Submit Application
            </Button>
          </div>
        </div>

        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <InfoIcon size={20} />
                Application Guidelines
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4 text-sm">
              <div>
                <h4 className="font-medium mb-1">Required Documents</h4>
                <ul className="list-disc list-inside text-muted-foreground space-y-1">
                  <li>Business plan (detailed)</li>
                  <li>Financial projections (5 years)</li>
                  <li>Proof of capital availability</li>
                  <li>Directors&apos; qualifications</li>
                  <li>AML/CFT policies</li>
                </ul>
              </div>
              <div>
                <h4 className="font-medium mb-1">Minimum Capital Requirements</h4>
                <ul className="text-muted-foreground space-y-1">
                  <li>Commercial: RWF 5 billion</li>
                  <li>Microfinance: RWF 500 million</li>
                  <li>Development: RWF 3 billion</li>
                  <li>Cooperative: RWF 300 million</li>
                </ul>
              </div>
              <div>
                <h4 className="font-medium mb-1">Process Timeline</h4>
                <p className="text-muted-foreground">
                  Standard review takes 30-90 days. You will be notified if additional information is required.
                </p>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Upload Documents</CardTitle>
              <CardDescription>
                Documents can be uploaded after creating the application
              </CardDescription>
            </CardHeader>
            <CardContent>
              <p className="text-sm text-muted-foreground">
                Save your application first, then you can upload supporting documents from the application detail page.
              </p>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}
